import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import kotlinx.coroutines.launch

class MainActivity : AppCompatActivity() {
    private val userRepository = UserRepository()
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        NetworkModule.setEnvironment(Environment.PRODUCTION)
        NetworkModule.setAuthToken("your_auth_token_here")
        
        fetchUsers()
    }
    
    private fun fetchUsers() {
        lifecycleScope.launch {
            when (val response = userRepository.getUsers()) {
                is ApiResponse.Success -> {
                    Log.d("MainActivity", "Users: ${response.data}")
                }
                is ApiResponse.Error -> {
                    Log.e("MainActivity", "Error: ${response.message}")
                }
                is ApiResponse.Loading -> {
                    Log.d("MainActivity", "Loading...")
                }
            }
        }
    }
    
    private fun fetchUserById(userId: Int) {
        lifecycleScope.launch {
            when (val response = userRepository.getUserById(userId)) {
                is ApiResponse.Success -> {
                    Log.d("MainActivity", "User: ${response.data}")
                }
                is ApiResponse.Error -> {
                    Log.e("MainActivity", "Error: ${response.message}")
                }
                is ApiResponse.Loading -> {
                    Log.d("MainActivity", "Loading...")
                }
            }
        }
    }
